import React from "react";
import { useLocation, useNavigate, Link } from "react-router-dom";
import { DIFFICULTY_COLORS } from "../utils/algorithms";

export default function ResultsPage() {
  const { state }  = useLocation();
  const navigate   = useNavigate();

  if (!state?.result) {
    return (
      <div style={{ textAlign: "center", padding: "4rem" }}>
        <p>No results found.</p>
        <Link to="/topics" className="btn btn-primary" style={{ marginTop: "1rem" }}>Back to Topics</Link>
      </div>
    );
  }

  const { result, topic, questions } = state;
  const {
    score, maxPossibleScore, percentage, passed,
    correctCount, wrongCount, maxStreak, totalStreakBonus, history,
  } = result;

  const questionMap = new Map((questions || []).map((q) => [q._id, q]));

  const gradeColor = percentage >= 80 ? "var(--success)" : percentage >= 60 ? "var(--warning)" : "var(--error)";
  const gradeLabel = percentage >= 80 ? "Excellent!" : percentage >= 60 ? "Good job!" : "Keep practising";

  return (
    <div className="fade-in" style={{ maxWidth: 700, margin: "0 auto" }}>
      {/* Result hero */}
      <div className="card" style={{ textAlign: "center", marginBottom: "1.5rem", padding: "2.5rem" }}>
        <div style={{ fontSize: "3.5rem", marginBottom: "0.5rem" }}>
          {passed ? "🎉" : "💪"}
        </div>
        <h1 style={{ fontSize: "2rem", marginBottom: "0.25rem", color: gradeColor }}>{gradeLabel}</h1>
        <p style={{ color: "var(--text-2)", marginBottom: "2rem" }}>{topic?.name || "Quiz"} complete</p>

        {/* Score ring simulation */}
        <div style={{
          width:        120, height: 120, borderRadius: "50%",
          border:       `8px solid var(--bg-3)`,
          boxShadow:    `inset 0 0 0 8px ${gradeColor}22, 0 0 32px ${gradeColor}44`,
          display:      "flex", flexDirection: "column",
          alignItems:   "center", justifyContent: "center",
          margin:       "0 auto 2rem",
          position:     "relative",
          background:   `conic-gradient(${gradeColor} ${percentage * 3.6}deg, var(--bg-3) 0deg)`,
        }}>
          <div style={{
            width: 96, height: 96, borderRadius: "50%",
            background: "var(--bg-2)",
            display: "flex", flexDirection: "column",
            alignItems: "center", justifyContent: "center",
            position: "absolute",
          }}>
            <span style={{ fontFamily: "var(--font-display)", fontSize: "1.75rem", fontWeight: 800, color: gradeColor }}>
              {percentage}%
            </span>
          </div>
        </div>

        {/* Stats grid */}
        <div style={{ display: "grid", gridTemplateColumns: "repeat(3, 1fr)", gap: "1rem" }}>
          {[
            { label: "Score",         value: `${score} / ${maxPossibleScore}`, color: gradeColor },
            { label: "Correct",       value: correctCount, color: "var(--success)" },
            { label: "Wrong",         value: wrongCount,   color: "var(--error)" },
            { label: "Max Streak",    value: `${maxStreak}×`, color: "var(--warning)" },
            { label: "Streak Bonus",  value: `+${totalStreakBonus}`, color: "var(--accent)" },
            { label: "Result",        value: passed ? "PASSED ✅" : "FAILED ❌", color: passed ? "var(--success)" : "var(--error)" },
          ].map(({ label, value, color }) => (
            <div key={label} style={{
              background: "var(--bg-3)", borderRadius: "var(--radius-sm)", padding: "0.9rem",
              border: "1px solid var(--border)",
            }}>
              <div style={{ color, fontFamily: "var(--font-display)", fontWeight: 700, fontSize: "1.1rem" }}>{value}</div>
              <div style={{ color: "var(--text-3)", fontSize: "0.78rem", marginTop: "0.2rem" }}>{label}</div>
            </div>
          ))}
        </div>

        {/* Action buttons */}
        <div style={{ display: "flex", gap: "0.75rem", justifyContent: "center", marginTop: "1.75rem", flexWrap: "wrap" }}>
          <button
            className="btn btn-ghost"
            onClick={() => navigate(`/quiz/${topic?._id || ""}`, { state: { topic } })}
          >
            🔄 Retake Quiz
          </button>
          <Link to="/topics" className="btn btn-primary">📚 More Topics →</Link>
          <Link to="/leaderboard" className="btn btn-ghost">🏆 Leaderboard</Link>
        </div>
      </div>

      {/* Per-question breakdown */}
      {history && history.length > 0 && (
        <div className="card">
          <h2 style={{ fontFamily: "var(--font-display)", marginBottom: "1.25rem", fontSize: "1.2rem" }}>
            Question Breakdown
          </h2>
          <div style={{ display: "flex", flexDirection: "column", gap: "0.75rem" }}>
            {history.map((h, i) => {
              const q = questionMap.get(h.questionId) || {};
              const isCorrect = h.result === "correct";
              const isTimeout = h.result === "timeout";

              return (
                <div
                  key={i}
                  style={{
                    background:   "var(--bg-3)", borderRadius: "var(--radius-sm)",
                    padding:      "0.9rem 1rem", border: "1px solid var(--border)",
                    borderLeft:   `3px solid ${isCorrect ? "var(--success)" : isTimeout ? "var(--warning)" : "var(--error)"}`,
                  }}
                >
                  <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", gap: "1rem" }}>
                    <div style={{ flex: 1 }}>
                      <div style={{ fontSize: "0.82rem", color: "var(--text-3)", marginBottom: "0.25rem" }}>
                        Q{i + 1} • <span style={{ color: DIFFICULTY_COLORS[q.difficulty] || "var(--text-2)" }}>{q.difficulty}</span>
                      </div>
                      <div style={{ fontSize: "0.9rem", color: "var(--text)", lineHeight: 1.4 }}>
                        {h.questionText || q.text || "(question)"}
                      </div>
                      {(h.explanation || q.explanation) && (
                        <div style={{ fontSize: "0.8rem", color: "var(--text-2)", marginTop: "0.4rem", lineHeight: 1.4 }}>
                          💡 {h.explanation || q.explanation}
                        </div>
                      )}
                    </div>
                    <div style={{ textAlign: "right", flexShrink: 0 }}>
                      <div style={{ fontSize: "1.1rem" }}>
                        {isCorrect ? "✅" : isTimeout ? "⏰" : "❌"}
                      </div>
                      <div style={{
                        fontFamily: "var(--font-display)", fontWeight: 700, fontSize: "0.9rem",
                        color: h.scoreChange > 0 ? "var(--success)" : h.scoreChange < 0 ? "var(--error)" : "var(--text-3)",
                      }}>
                        {h.scoreChange > 0 ? "+" : ""}{h.scoreChange}
                      </div>
                      {h.streakBonus > 0 && (
                        <div style={{ fontSize: "0.75rem", color: "var(--warning)" }}>
                          🔥 +{h.streakBonus} bonus
                        </div>
                      )}
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      )}
    </div>
  );
}
